#include <stdio.h>
#include <stdlib.h>
#include <string.h>

struct Student {
    int roll;
    char name[30];
    float marks;
};

int main() {
    // Allocate memory for one structure
    struct Student *ptr = (struct Student *)malloc(sizeof(struct Student));

    // Check if allocation succeeded
    if (ptr == NULL) {
        printf("Memory allocation failed\n");
        return 1;
    }

    // Initialize using arrow operator
    ptr->roll = 101;
    strcpy(ptr->name, "Amit Kumar");
    ptr->marks = 85.5;

    // Display values
    printf("Roll: %d\n", ptr->roll);
    printf("Name: %s\n", ptr->name);
    printf("Marks: %.2f\n", ptr->marks);

    // Free memory and set pointer to NULL
    free(ptr);
    ptr = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

struct Node {
    int data;
    struct Node *next;
};

// Function to create a new node
struct Node* createNode(int value) {
    struct Node *newNode = (struct Node *)malloc(sizeof(struct Node));
    if (newNode == NULL) {
        printf("Memory allocation failed\n");
        exit(1);
    }
    newNode->data = value;
    newNode->next = NULL;
    return newNode;
}

// Function to display linked list
void displayList(struct Node *head) {
    struct Node *temp = head;
    while (temp != NULL) {
        printf("%d -> ", temp->data);
        temp = temp->next;
    }
    printf("NULL\n");
}

// Function to count nodes
int countNodes(struct Node *head) {
    int count = 0;
    struct Node *temp = head;
    while (temp != NULL) {
        count++;
        temp = temp->next;
    }
    return count;
}

int main() {
    // Create linked list: 10 -> 20 -> 30 -> NULL
    struct Node *head = createNode(10);
    head->next = createNode(20);
    head->next->next = createNode(30);

    printf("Linked List: ");
    displayList(head);

    printf("Total nodes: %d\n", countNodes(head));

    // Free all nodes
    struct Node *temp;
    while (head != NULL) {
        temp = head;
        head = head->next;
        free(temp);
    }

    return 0;
}

#include <stdio.h>

struct Rectangle {
    int length;
    int width;
};

// Function to calculate area - pass by reference
void calculateArea(struct Rectangle *r) {
    // Using arrow operator to access members
    r->length = 20;  // Modifying original
    r->width = 15;   // Modifying original
}

// Function to display - pass by value (copy)
void displayRectangle(struct Rectangle r) {
    printf("Length: %d, Width: %d\n", r.length, r.width);
    printf("Area: %d\n", r.length * r.width);
}

int main() {
    struct Rectangle rect = {10, 10};

    printf("Before function call:\n");
    displayRectangle(rect);

    // Pass address - function can modify original
    calculateArea(&rect);

    printf("\nAfter function call:\n");
    displayRectangle(rect);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

struct Book {
    char title[50];
    char author[50];
    float price;
};

int main() {
    // Array of 3 pointers to struct Book
    struct Book *library[3];

    // Allocate memory for each book
    for (int i = 0; i < 3; i++) {
        library[i] = (struct Book *)malloc(sizeof(struct Book));
        if (library[i] == NULL) {
            printf("Allocation failed\n");
            return 1;
        }
    }

    // Initialize books
    strcpy(library[0]->title, "C Programming");
    strcpy(library[0]->author, "Dennis Ritchie");
    library[0]->price = 350.00;

    strcpy(library[1]->title, "Data Structures");
    strcpy(library[1]->author, "Tremble");
    library[1]->price = 420.50;

    strcpy(library[2]->title, "Operating Systems");
    strcpy(library[2]->author, "Galvin");
    library[2]->price = 550.00;

    // Display all books
    printf("Library Collection:\n");
    printf("%-20s %-15s %s\n", "Title", "Author", "Price");
    printf("------------------------------------------------\n");

    for (int i = 0; i < 3; i++) {
        printf("%-20s %-15s %.2f\n", 
               library[i]->title, 
               library[i]->author, 
               library[i]->price);
    }

    // Free all allocated memory
    for (int i = 0; i < 3; i++) {
        free(library[i]);
    }

    return 0;
}
